class Solution {
    public int maxWeight(int[] weights) {
        Arrays.sort(weights);

        int n = weights.length;
        int bag1 = 0, bag2 = 0;

        for (int i = 0; i < n / 2; i++)
            bag1 += weights[n - 1 - i];

        for (int i = n / 2; i < n; i++)
            bag2 += weights[n - 1 - i];

        return Math.abs(bag1 - bag2);
    }
