            return false;

        for (int i = 2; i * i <= n; i++) {
            if (n % i == 0)
                return false;
        }

        return true;
    }

    public int minJumps(int[] nums) {
        int n = nums.length;
        int[] dist = new int[n];
        Arrays.fill(dist, Integer.MAX_VALUE);

        dist[0] = 0;

        for (int i = 0; i < n; i++) {
            if (i + 1 < n)
                dist[i + 1] = Math.min(dist[i + 1], dist[i] + 1);

            for (int j = i + 1; j < n; j++) {
                if (isPrime(Math.abs(nums[i] - nums[j])))
                    dist[j] = Math.min(dist[j], dist[i] + 1);
            }
        }

        return dist[n - 1];
    }
}

class Solution {
    public int minCostPath(int[][] grid) {
        int m = grid.length;
        int n = grid[0].length;

        int[][] dp = new int[m][n];

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                dp[i][j] = Integer.MAX_VALUE;
            }
        }

        dp[0][0] = grid[0][0];

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (i > 0)
                    dp[i][j] = Math.min(dp[i][j], dp[i - 1][j] + grid[i][j]);

                if (j > 0)
                    dp[i][j] = Math.min(dp[i][j], dp[i][j - 1] + grid[i][j]);
            }
        }

        return dp[m - 1][n - 1];
    }
}

