class Solution {
    public int minimumMoves(int[][] grid) {
        int n = grid.length;
        Queue<int[]> q = new LinkedList<>();
        boolean[][][] vis = new boolean[n][n][2];

        q.offer(new int[]{0,0,0,0});
        vis[0][0][0] = true;

        while (!q.isEmpty()) {
            int[] cur = q.poll();
            int x = cur[0], y = cur[1], d = cur[2], steps = cur[3];

            if (x == n-1 && y == n-2 && d == 0)
                return steps;

            if (d == 0) {
                if (y+2 < n && grid[x][y+2] == 0 && !vis[x][y+1][0]) {
                    vis[x][y+1][0] = true;
                    q.offer(new int[]{x,y+1,0,steps+1});
                }
            } else {
                if (x+2 < n && grid[x+2][y] == 0 && !vis[x+1][y][1]) {
                    vis[x+1][y][1] = true;
                    q.offer(new int[]{x+1,y,1,steps+1});
                }
            }
        }

        return -1;
    }
}

