    private int dfs(int i, int n, int[] cost) {
        if (i > n)
            return 0;

        int left = dfs(2*i, n, cost);
        int right = dfs(2*i+1, n, cost);

        ans += Math.abs(left-right);

        return cost[i-1] + Math.max(left, right);
    }
}

