class DSU {
    int[] p;

    DSU(int n) {
        p = new int[n];
        for (int i = 0; i < n; i++)
            p[i] = i;
    }

    int find(int x) {
        if (p[x] != x)
            p[x] = find(p[x]);
        return p[x];
    }

    boolean union(int a, int b) {
        int pa = find(a), pb = find(b);
        if (pa == pb) return false;
        p[pa] = pb;
        return true;
    }
}

class Solution {
    public int minimumTime(int n, int[][] edges, int k) {
        Arrays.sort(edges, (a,b)->a[2]-b[2]);
        DSU dsu = new DSU(n);
        int comp = n;

        for (int[] e : edges) {
            if (dsu.union(e[0], e[1]))
                comp--;

            if (comp <= k)
                return e[2];
        }

        return -1;
    }
}

