        List<Integer>[] tree = new ArrayList[n];

        for (int i = 0; i < n; i++)
            tree[i] = new ArrayList<>();

        for (int i = 1; i < n; i++)
            tree[parent[i]].add(i);

        dfs(0, tree, values);

        return ans;
    }

    private long dfs(int node, List<Integer>[] tree, int[] values) {
        long sum = values[node];

        for (int child : tree[node]) {
            sum += dfs(child, tree, values);
        }

        ans += sum;
        return sum;
    }
}

