class Solution {
    public int maxProfit(int[] prices) {
        int profit = 0;

        for (int i = 1; i < prices.length; i++) {
            if (prices[i] > prices[i - 1])
                profit += prices[i] - prices[i - 1];
        }

        return profit;
    }
}

class Solution {
    public String resultingString(String s) {
        StringBuilder stack = new StringBuilder();

        for (char c : s.toCharArray()) {
            int len = stack.length();

            if (len > 0 && stack.charAt(len - 1) == c)
                stack.deleteCharAt(len - 1);
            else
                stack.append(c);
        }

        return stack.toString();
    }
}

class Solution {
    public int minOperations(int[] nums, int k) {
        int sum = 0;

        for (int num : nums)
            sum += num;

        return (k - (sum % k)) % k;
    }
}

import java.util.*;

class Solution {
    public int minSwaps(int[] nums) {
        int n = nums.length;
        int[][] arr = new int[n][2];

        for (int i = 0; i < n; i++) {
            arr[i][0] = digitSum(nums[i]);
            arr[i][1] = i;
        }

        Arrays.sort(arr, (a, b) -> a[0] - b[0]);

        boolean[] visited = new boolean[n];
        int swaps = 0;

        for (int i = 0; i < n; i++) {
            if (visited[i] || arr[i][1] == i)
                continue;

            int cycle = 0;
            int j = i;

            while (!visited[j]) {
                visited[j] = true;
                j = arr[j][1];
                cycle++;
            }

            swaps += cycle - 1;
        }

        return swaps;
    }

    private int digitSum(int n) {
        int sum = 0;

        while (n > 0) {
            sum += n % 10;
            n /= 10;
        }

        return sum;
    }
}

class Solution {
    public boolean canPartitionGrid(int[][] grid) {
        int total = 0;

        for (int[] row : grid) {
            for (int val : row)
                total += val;
        }

        int prefix = 0;

        for (int[] row : grid) {
            for (int val : row)
                prefix += val;

            if (prefix * 2 == total)
                return true;
        }

        return false;
    }
}

